<section class="admin-page-head"><div><p class="eyebrow">CONȚINUT</p><h1>CMS și pagini</h1></div><a class="admin-button" href="<?= e(url('/admin/cms/homepage')) ?>">Editează homepage</a></section><section class="cms-grid"><?php foreach($sections as $section): ?><form class="admin-panel" method="post" action="<?= e(url('/admin/cms')) ?>"><?= csrf_field() ?><input type="hidden" name="section_key" value="<?= e($section['section_key']) ?>"><h2><?= e(ucwords(str_replace('_',' ',$section['section_key']))) ?></h2><label>Titlu<input name="title" value="<?= e($section['title']) ?>"></label><label class="check-label"><input type="checkbox" name="is_active" value="1" <?= $section['is_active']?'checked':'' ?>> Secțiune activă</label><button class="admin-button secondary" type="submit">Salvează</button></form><?php endforeach; ?></section><section class="admin-panel"><div class="panel-head"><h2>Pagini publice și legale</h2></div><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Pagină</th><th>Slug</th><th>Status</th><th>Actualizat</th></tr></thead><tbody><?php foreach($pages as $page): ?><tr><td><a href="<?= e(url('/admin/cms/pagini/'.$page['id'])) ?>"><strong><?= e($page['title']) ?></strong></a></td><td><?= e($page['slug']) ?></td><td><?= e($page['status']) ?></td><td><?= date('d.m.Y',strtotime($page['updated_at'])) ?></td></tr><?php endforeach; ?></tbody></table></div></section>

